package gui; import javax.swing.*; import java.awt.*; 
public class MainForm extends JFrame { public MainForm(String role, String name, int userId) { setTitle("Architecture System - " + role); setExtendedState(JFrame.MAXIMIZED_BOTH); setDefaultCloseOperation(EXIT_ON_CLOSE); setLayout(new BorderLayout()); JPanel top = new JPanel(new GridLayout(2,1)); top.setBackground(new Color(25, 25, 50)); JLabel title = new JLabel("Hello " + role.toUpperCase(), SwingConstants.CENTER); title.setForeground(Color.WHITE); title.setFont(new Font("Segoe UI", Font.BOLD, 44)); JLabel sub = new JLabel("Welcome, " + name, SwingConstants.CENTER); sub.setForeground(new Color(180,180,180)); sub.setFont(new Font("Segoe UI", Font.PLAIN, 22)); top.add(title); top.add(sub); add(top, BorderLayout.NORTH); JPanel center = new JPanel(new GridBagLayout()); JPanel grid = new JPanel(new GridLayout(2, 3, 30, 30)); grid.setBackground(Color.WHITE); JButton projects = createButton("Projects"); JButton employees = createButton("Employees"); JButton clients = createButton("Clients"); JButton account = createButton("My Account"); if (role.equals("ADMIN")) { grid.add(createLabel("All Projects")); grid.add(createLabel("Employees")); grid.add(createLabel("Clients")); grid.add(projects); grid.add(employees); grid.add(clients); } else if (role.equals("EMPLOYEE")) { grid.add(createLabel("My Projects")); grid.add(createLabel("My Account")); grid.add(projects); grid.add(account); } else if (role.equals("CLIENT")) { grid.add(createLabel("My Projects")); grid.add(createLabel("My Account")); grid.add(projects); grid.add(account); } center.add(grid); add(center, BorderLayout.CENTER); JButton logout = new JButton("Logout"); logout.setPreferredSize(new Dimension(180, 45)); logout.setFont(new Font("Segoe UI", Font.BOLD, 16)); logout.setBackground(new Color(200, 60, 60)); logout.setForeground(Color.WHITE); logout.addActionListener(e -> { new LoginForm(); dispose(); }); JPanel bottom = new JPanel(); bottom.add(logout); add(bottom, BorderLayout.SOUTH);
                                                                                                                                                    projects.addActionListener(e -> new ProjectTableForm(role, userId)); employees.addActionListener(e -> { if (role.equals("ADMIN")) { new EmployeeTableForm(role, userId); } }); clients.addActionListener(e -> { if (role.equals("ADMIN")) { new ClientTableForm(role, userId); } }); account.addActionListener(e -> { if (role.equals("EMPLOYEE")) { new EmployeeTableForm("EMPLOYEE", userId); } else if (role.equals("CLIENT")) { new ClientForm("CLIENT", userId); } }); setVisible(true); } private JButton createButton(String text) { JButton btn = new JButton(text); btn.setPreferredSize(new Dimension(220, 90)); btn.setFont(new Font("Segoe UI", Font.BOLD, 20)); btn.setBackground(new Color(70, 90, 160)); btn.setForeground(Color.WHITE); btn.setFocusPainted(false); return btn; } private JLabel createLabel(String text) { JLabel lbl = new JLabel(text, SwingConstants.CENTER); lbl.setFont(new Font("Segoe UI", Font.BOLD, 16)); lbl.setForeground(new Color(80, 80, 80)); return lbl; } }
